static int is_blank_string(const char *s) {
    if (!s)
        return 1;
    while (*s) {
        if (!isspace((unsigned char)*s))
            return 0;
        s++;
    }
    return 1;
}

static char *json_get_string_field(const char *json, const char *field) {
    if (!json || !field)
        return NULL;
    char pat[128];
    snprintf(pat, sizeof(pat), "\"%s\"", field);
    const char *p = strstr(json, pat);
    if (!p)
        return NULL;
    p += strlen(pat);
    while (*p && isspace((unsigned char)*p))
        p++;
    if (*p != ':')
        return NULL;
    p++;
    while (*p && isspace((unsigned char)*p))
        p++;
    if (*p != '"')
        return NULL;
    p++;

    size_t cap = 64, len = 0;
    char *out = malloc(cap);
    if (!out)
        return NULL;
    while (*p) {
        if (*p == '"') {
            out[len] = '\0';
            return out;
        }
        unsigned char ch = (unsigned char)*p;
        if (ch == '\\') {
            p++;
            if (!*p)
                break;
            switch (*p) {
            case '"': ch = '"'; break;
            case '\\': ch = '\\'; break;
            case '/': ch = '/'; break;
            case 'b': ch = '\b'; break;
            case 'f': ch = '\f'; break;
            case 'n': ch = '\n'; break;
            case 'r': ch = '\r'; break;
            case 't': ch = '\t'; break;
            default: ch = (unsigned char)*p; break;
            }
        }
        if (len + 2 > cap) {
            cap *= 2;
            char *n = realloc(out, cap);
            if (!n) {
                free(out);
                return NULL;
            }
            out = n;
        }
        out[len++] = (char)ch;
        p++;
    }
    free(out);
    return NULL;
}

static int parse_int_param(struct MHD_Connection *connection, const char *name, int defv) {
    const char *v = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, name);
    if (!v || *v == '\0')
        return defv;
    char *end = NULL;
    long x = strtol(v, &end, 10);
    if (!end || *end != '\0')
        return defv;
    if (x < 0)
        return defv;
    if (x > 1000000000L)
        x = 1000000000L;
    return (int)x;
}

static int parse_id_from_url(const char *url, int *out_id) {
    const char *prefix = "/api/notes/";
    size_t n = strlen(prefix);
    if (strncmp(url, prefix, n) != 0)
        return 0;
    const char *p = url + n;
    if (*p == '\0')
        return 0;
    char *end = NULL;
    long id = strtol(p, &end, 10);
    if (!end || *end != '\0')
        return 0;
    if (id < 0 || id > 2147483647L)
        return 0;
    *out_id = (int)id;
    return 1;
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {
    if (*con_cls == NULL) {
        struct connection_info *ci = calloc(1, sizeof(*ci));
        if (!ci)
            return MHD_NO;
        *con_cls = ci;
        return MHD_YES;
    }

    struct connection_info *ci = (struct connection_info *)(*con_cls);

    if ((strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0) && *upload_data_size > 0) {
        if (ci->data_size + *upload_data_size > NOTES_MAX_BODY_BYTES) {
            *upload_data_size = 0;
            return send_json(connection, "{\"error\":\"payload too large\"}", MHD_HTTP_PAYLOAD_TOO_LARGE);
        }
        char *n = realloc(ci->data, ci->data_size + *upload_data_size + 1);
        if (!n)
            return MHD_NO;
        ci->data = n;
        memcpy(ci->data + ci->data_size, upload_data, *upload_data_size);
        ci->data_size += *upload_data_size;
        ci->data[ci->data_size] = '\0';
        *upload_data_size = 0;
        return MHD_YES;
    }

    if (strcmp(method, "OPTIONS") == 0)
        return send_json(connection, "", MHD_HTTP_OK);

    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "GET") == 0) {
        int limit = parse_int_param(connection, "limit", NOTES_DEFAULT_PAGE_SIZE);
        int offset = parse_int_param(connection, "offset", 0);
        if (limit > NOTES_MAX_PAGE_SIZE)
            limit = NOTES_MAX_PAGE_SIZE;

        int total = get_total_notes_count();
        char *json = get_notes_paginated_json(limit, offset);
        if (!json)
            return send_json_with_total(connection, "[]", MHD_HTTP_OK, total);
        enum MHD_Result r = send_json_with_total(connection, json, MHD_HTTP_OK, total);
        free(json);
        return r;
    }

    int id = 0;
    if (parse_id_from_url(url, &id)) {
        if (strcmp(method, "GET") == 0) {
            char *json = get_note_json(id);
            if (!json)
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            enum MHD_Result r = send_json(connection, json, MHD_HTTP_OK);
            free(json);
            return r;
        }

        if (strcmp(method, "PUT") == 0) {
            if (!api_key_valid(connection))
                return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
            if (!note_exists(id))
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);

            const char *body = ci->data ? ci->data : "";
            char *title = json_get_string_field(body, "title");
            char *content = json_get_string_field(body, "content");
            if (!title || is_blank_string(title)) {
                free(title);
                free(content);
                return send_json(connection, "{\"error\":\"invalid title\"}", MHD_HTTP_BAD_REQUEST);
            }
            if (!content)
                content = strdup("");

            int ok = update_note(id, title, content);
            free(title);
            free(content);
            if (ok <= 0)
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);

            char *json = get_note_json(id);
            if (!json)
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            enum MHD_Result r = send_json(connection, json, MHD_HTTP_OK);
            free(json);
            return r;
        }

        if (strcmp(method, "DELETE") == 0) {
            if (!api_key_valid(connection))
                return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
            int ok = delete_note(id);
            if (ok <= 0)
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
        }
    }

    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "POST") == 0) {
        if (!api_key_valid(connection))
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);

        const char *body = ci->data ? ci->data : "";
        char *title = json_get_string_field(body, "title");
        char *content = json_get_string_field(body, "content");
        if (!title || is_blank_string(title)) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"invalid title\"}", MHD_HTTP_BAD_REQUEST);
        }
        if (!content)
            content = strdup("");

        int new_id = create_note(title, content);
        free(title);
        free(content);
        if (new_id <= 0)
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);

        char *json = get_note_json(new_id);
        if (!json)
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        enum MHD_Result r = send_json(connection, json, MHD_HTTP_CREATED);
        free(json);
        return r;
    }

    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}
