static const char *get_content_type(const char *path) {
    const char *ext = strrchr(path, '.');
    if (!ext) return "application/octet-stream";
    if (strcmp(ext, ".html") == 0) return "text/html";
    if (strcmp(ext, ".css") == 0) return "text/css";
    if (strcmp(ext, ".js") == 0) return "application/javascript";
    return "application/octet-stream";
}

static int hexval(int c){
    if (c>='0' && c<='9') return c-'0';
    if (c>='a' && c<='f') return 10 + (c-'a');
    if (c>='A' && c<='F') return 10 + (c-'A');
    return -1;
}

static int url_decode(const char *in, char *out, size_t outsz){
    size_t oi=0;
    for (size_t i=0; in[i]; i++){
        unsigned char ch = (unsigned char)in[i];
        if (ch=='%'){
            int a = hexval((unsigned char)in[i+1]);
            int b = hexval((unsigned char)in[i+2]);
            if (a<0 || b<0) return -1;
            ch = (unsigned char)((a<<4)|b);
            i += 2;
        }
        if (ch==0) return -1;
        if (oi+1>=outsz) return -1;
        out[oi++] = (char)ch;
    }
    out[oi]=0;
    return 0;
}

static int decoded_path_has_dotdot(const char *url){
    char dec[4096];
    if (url_decode(url, dec, sizeof(dec))!=0) return 0;
    const char *p = dec;
    while (*p){
        while (*p=='/') p++;
        if (!*p) break;
        const char *seg=p;
        while (*p && *p!='/') p++;
        size_t len = (size_t)(p-seg);
        if (len==2 && seg[0]=='.' && seg[1]=='.') return 1;
    }
    return 0;
}

static int url_contains_encoded_dotdot(const char *url) {
    const char *p = url;
    while (*p) {
        if (strncasecmp(p, "%2e%2e", 6) == 0)
            return 1;
        p++;
    }
    return 0;
}

static enum MHD_Result serve_static_file(struct MHD_Connection *connection,
                                        const char *url) {
    if (strstr(url, "..") != NULL || url_contains_encoded_dotdot(url) || decoded_path_has_dotdot(url)) {
        struct MHD_Response *r = MHD_create_response_from_buffer(
            9, (void *)"Forbidden", MHD_RESPMEM_PERSISTENT);
        enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_FORBIDDEN, r);
        MHD_destroy_response(r);
        return ret;
    }

    char path[PATH_MAX];
    if (strcmp(url, "/") == 0)
        url = "/index.html";

    snprintf(path, sizeof(path), "%s%s", WWW_DIR, url);

    struct stat st;
    if (stat(path, &st) != 0 || !S_ISREG(st.st_mode)) {
        struct MHD_Response *r = MHD_create_response_from_buffer(
            9, (void *)"Not Found", MHD_RESPMEM_PERSISTENT);
        enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_NOT_FOUND, r);
        MHD_destroy_response(r);
        return ret;
    }

    FILE *f = fopen(path, "rb");
    if (!f) {
        struct MHD_Response *r = MHD_create_response_from_buffer(
            5, (void *)"Error", MHD_RESPMEM_PERSISTENT);
        enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_INTERNAL_SERVER_ERROR, r);
        MHD_destroy_response(r);
        return ret;
    }

    char *data = malloc(st.st_size);
    if (!data) {
        fclose(f);
        struct MHD_Response *r = MHD_create_response_from_buffer(
            5, (void *)"Error", MHD_RESPMEM_PERSISTENT);
        enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_INTERNAL_SERVER_ERROR, r);
        MHD_destroy_response(r);
        return ret;
    }

    size_t n = fread(data, 1, st.st_size, f);
    fclose(f);
    if (n != (size_t)st.st_size) {
        free(data);
        struct MHD_Response *r = MHD_create_response_from_buffer(
            5, (void *)"Error", MHD_RESPMEM_PERSISTENT);
        enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_INTERNAL_SERVER_ERROR, r);
        MHD_destroy_response(r);
        return ret;
    }

    struct MHD_Response *r = MHD_create_response_from_buffer(
        n, (void *)data, MHD_RESPMEM_MUST_FREE);
    MHD_add_response_header(r, "Content-Type", get_content_type(path));
    enum MHD_Result ret = MHD_queue_response(connection, MHD_HTTP_OK, r);
    MHD_destroy_response(r);
    return ret;
}

static void request_completed_cb(void *cls, struct MHD_Connection *connection,
                                 void **con_cls, enum MHD_RequestTerminationCode toe) {
    (void)cls;
    (void)connection;
    (void)toe;
    if (!con_cls || !*con_cls)
        return;
    struct connection_info *ci = (struct connection_info *)(*con_cls);
    free(ci->data);
    free(ci);
    *con_cls = NULL;
}

static enum MHD_Result access_handler(void *cls,
                                     struct MHD_Connection *connection,
                                     const char *url,
                                     const char *method,
                                     const char *version,
                                     const char *upload_data,
                                     size_t *upload_data_size,
                                     void **con_cls) {
    (void)cls;
    (void)version;

    if (strncmp(url, "/api/", 5) == 0)
        return route_request(connection, url, method, upload_data, upload_data_size, con_cls);
    return serve_static_file(connection, url);
}

int main(void) {
    signal(SIGINT, handle_signal);
    signal(SIGTERM, handle_signal);

    if (init_db("/app/data/notes.db") != 0) {
        fprintf(stderr, "Failed to initialize database\n");
        return 1;
    }

    daemon_handle = MHD_start_daemon(MHD_USE_INTERNAL_POLLING_THREAD,
                                    PORT,
                                    NULL, NULL,
                                    &access_handler, NULL,
                                    MHD_OPTION_NOTIFY_COMPLETED, request_completed_cb, NULL,
                                    MHD_OPTION_END);

    if (!daemon_handle) {
        fprintf(stderr, "Failed to start server: %s\n", strerror(errno));
        return 1;
    }

    printf("Server running on port %d\n", PORT);
    while (1) pause();
    return 0;
}
