        return NULL;

    int n = snprintf(buf, cap, "{\"id\":%d,\"title\":\"", rid);
    if (n < 0) {
        free(buf);
        return NULL;
    }
    len = (size_t)n;
    buf[len] = '\0';
    json_append_escaped(&buf, &cap, &len, title);

    const char *mid = "\",\"content\":\"";
    size_t mn = strlen(mid);
    if (len + mn + 1 >= cap) {
        size_t ncap = cap * 2;
        while (len + mn + 1 >= ncap)
            ncap *= 2;
        char *nbuf = realloc(buf, ncap);
        if (!nbuf) {
