        char *nbuf = realloc(buf, len + en + 1);
        if (!nbuf) {
            free(buf);
            return NULL;
        }
        buf = nbuf;
        cap = len + en + 1;
    }
    memcpy(buf + len, end, en);
    len += en;
    buf[len] = '\0';
    return buf;
}

int update_note(int id, const char *title, const char *content) {
    if (!db)
        return -1;
    if (begin_immediate() != 0)
        return -1;

    sqlite3_stmt *stmt = NULL;
    const char *sql = "UPDATE notes SET title = ?, content = ? WHERE id = ?;";
    if (sqlite3_prepare_v2(db, sql, -1, &stmt, NULL) != SQLITE_OK) {
        rollback_tx();
        return -1;
    }
    sqlite3_bind_text(stmt, 1, title ? title : "", -1, SQLITE_TRANSIENT);
    sqlite3_bind_text(stmt, 2, content ? content : "", -1, SQLITE_TRANSIENT);
    sqlite3_bind_int(stmt, 3, id);
    int rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);
    if (rc != SQLITE_DONE) {
        rollback_tx();
        return -1;
    }
    int changed = sqlite3_changes(db);
    if (commit_tx() != 0)
        return -1;
    return changed > 0 ? 1 : 0;
}

int delete_note(int id) {
    if (!db)
        return -1;
    if (begin_immediate() != 0)
        return -1;

    sqlite3_stmt *stmt = NULL;
    const char *sql = "DELETE FROM notes WHERE id = ?;";
    if (sqlite3_prepare_v2(db, sql, -1, &stmt, NULL) != SQLITE_OK) {
        rollback_tx();
        return -1;
    }
    sqlite3_bind_int(stmt, 1, id);
    int rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);
    if (rc != SQLITE_DONE) {
        rollback_tx();
        return -1;
    }
    int changed = sqlite3_changes(db);
    if (commit_tx() != 0)
        return -1;
    return changed > 0 ? 1 : 0;
}

int note_exists(int id) {
    if (!db)
        return 0;
    sqlite3_stmt *stmt = NULL;
    const char *sql = "SELECT 1 FROM notes WHERE id = ?;";
    if (sqlite3_prepare_v2(db, sql, -1, &stmt, NULL) != SQLITE_OK)
        return 0;
    sqlite3_bind_int(stmt, 1, id);
    int exists = (sqlite3_step(stmt) == SQLITE_ROW);
    sqlite3_finalize(stmt);
    return exists;
}
