static int is_blank_string(const char *s) {
    if (!s)
        return 1;
    while (*s) {
        if (!isspace((unsigned char)*s))
            return 0;
        s++;
    }
    return 1;
}

static char *json_get_string_field(const char *json, const char *field) {
    if (!json || !field)
        return NULL;
    char pat[128];
    snprintf(pat, sizeof(pat), "\"%s\"", field);
    const char *p = strstr(json, pat);
    if (!p)
        return NULL;
    p += strlen(pat);
    while (*p && isspace((unsigned char)*p))
        p++;
    if (*p != ':')
        return NULL;
    p++;
    while (*p && isspace((unsigned char)*p))
        p++;
    if (*p != '"')
        return NULL;
    p++;

    size_t cap = 64, len = 0;
    char *out = malloc(cap);
    if (!out)
        return NULL;
    while (*p) {
        if (*p == '"') {
            out[len] = '\0';
            return out;
        }
        unsigned char ch = (unsigned char)*p;
        if (ch == '\\') {
            p++;
            if (!*p)
                break;
            switch (*p) {
            case '"': ch = '"'; break;
            case '\\': ch = '\\'; break;
            case '/': ch = '/'; break;
            case 'b': ch = '\b'; break;
            case 'f': ch = '\f'; break;
            case 'n': ch = '\n'; break;
            case 'r': ch = '\r'; break;
            case 't': ch = '\t'; break;
            default: ch = (unsigned char)*p; break;
            }
        }
        if (len + 2 > cap) {
            cap *= 2;
            char *n = realloc(out, cap);
            if (!n) {
                free(out);
                return NULL;
            }
            out = n;
        }
        out[len++] = (char)ch;
        p++;
    }
    free(out);
    return NULL;
}

static int parse_int_param(struct MHD_Connection *connection, const char *name, int defv) {
    const char *v = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, name);
    if (!v || *v == '\0')
        return defv;
    char *end = NULL;
    long x = strtol(v, &end, 10);
    if (!end || *end != '\0')
        return defv;
    if (x < 0)
        return defv;
    if (x > 1000000000L)
        x = 1000000000L;
    return (int)x;
}

static int parse_id_from_url(const char *url, int *out_id) {
    const char *prefix = "/api/notes/";
