}

static enum MHD_Result access_handler(void *cls,
                                     struct MHD_Connection *connection,
                                     const char *url,
                                     const char *method,
                                     const char *version,
                                     const char *upload_data,
                                     size_t *upload_data_size,
                                     void **con_cls) {
    (void)cls;
    (void)version;

    if (strncmp(url, "/api/", 5) == 0) {
        return route_request(connection, url, method, upload_data, upload_data_size, con_cls);
    }
    return serve_static_file(connection, url);
}

int main(void) {
    signal(SIGINT, handle_signal);
    signal(SIGTERM, handle_signal);

    if (init_db("/app/data/notes.db") != 0) {
        fprintf(stderr, "Failed to initialize database\n");
        return 1;
    }

    daemon_handle = MHD_start_daemon(MHD_USE_INTERNAL_POLLING_THREAD,
                                    PORT,
                                    NULL, NULL,
                                    &access_handler, NULL,
                                    MHD_OPTION_NOTIFY_COMPLETED, request_completed_cb, NULL,
                                    MHD_OPTION_END);

    if (!daemon_handle) {
        fprintf(stderr, "Failed to start server: %s\n", strerror(errno));
        return 1;
    }

    printf("Server running on port %d\n", PORT);
    while (1) pause();
    return 0;
}
