    buf[len] = '\0';
    json_append_escaped(&buf, &cap, &len, title);

    const char *mid = "\",\"content\":\"";
    size_t mn = strlen(mid);
    if (len + mn + 1 >= cap) {
        size_t ncap = cap * 2;
        while (len + mn + 1 >= ncap)
            ncap *= 2;
        char *nbuf = realloc(buf, ncap);
        if (!nbuf) {
            free(buf);
            return NULL;
        }
        buf = nbuf;
        cap = ncap;
    }
    memcpy(buf + len, mid, mn);
    len += mn;
    buf[len] = '\0';
    json_append_escaped(&buf, &cap, &len, content);

    const char *end = "\"}";
    size_t en = strlen(end);
    if (len + en + 1 >= cap) {
        char *nbuf = realloc(buf, len + en + 1);
        if (!nbuf) {
            free(buf);
            return NULL;
        }
        buf = nbuf;
        cap = len + en + 1;
    }
    memcpy(buf + len, end, en);
    len += en;
    buf[len] = '\0';
    return buf;
}

